function parseQueryTimeSec(v) {
  if (v == null) return 0;
  if (typeof v === 'number') return v;
  const s = String(v).trim();
  const parts = s.split(':');
  if (parts.length === 3) {
    const h = Number(parts[0]) || 0;
    const m = Number(parts[1]) || 0;
    const sec = Number(parts[2]) || 0;
    return h * 3600 + m * 60 + sec;
  }
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function fmtDuration(sec) {
  const n = Number(sec);
  if (!Number.isFinite(n) || n <= 0) return '—';
  if (n >= 1) return `${n.toFixed(3)} s`;
  if (n >= 0.001) return `${(n * 1000).toFixed(1)} ms`;
  return `${(n * 1e6).toFixed(0)} µs`;
}

function fmtTime(ts) {
  if (!ts) return '—';
  const d = new Date(ts);
  if (!Number.isNaN(d.getTime())) {
    return d.toLocaleString(undefined, { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }
  return String(ts).replace('T', ' ').slice(0, 19);
}

function sqlPreview(sql, max = 72) {
  const s = String(sql ?? '').replace(/\s+/g, ' ').trim();
  if (!s) return '—';
  return s.length > max ? `${s.slice(0, max)}…` : s;
}

function isOn(v) {
  const s = String(v ?? '').toUpperCase();
  return s === 'ON' || s === '1' || s === 'TRUE' || s === 'YES';
}

function StatusBadge({ value }) {
  const on = isOn(value);
  return (
    <span
      className={`inline-flex items-center px-2 py-0.5 rounded-full text-2xs font-semibold ${
        on ? 'bg-emerald-900/40 text-emerald-400' : 'bg-nv-panel text-nv-textMuted border border-nv-border'
      }`}
    >
      {on ? 'ON' : 'OFF'}
    </span>
  );
}

