function ConfigSection({ section, config, expanded, onToggle }) {
  const Icon = section.icon;
  const hasData = section.keys.some((k) => config[k.key] != null && config[k.key] !== '');
  if (!hasData && Object.keys(config).length > 0) return null;

  return (
    <div className="border border-nv-border rounded-lg overflow-hidden bg-nv-panel/30">
      <button
        type="button"
        className="w-full px-3 py-2 flex items-center gap-2 text-left hover:bg-nv-hover/60 border-b border-nv-border/60"
        onClick={onToggle}
      >
        {expanded ? <ChevronDown size={14} className="text-sky-500 shrink-0" /> : <ChevronRight size={14} className="text-nv-textMuted shrink-0" />}
        <Icon size={14} className="text-sky-500 shrink-0" />
        <span className="text-xs font-semibold flex-1">{section.title}</span>
        {section.keys[0]?.kind === 'status' && config[section.keys[0].key] != null && (
          <StatusBadge value={config[section.keys[0].key]} />
        )}
      </button>
      {expanded && (
        <div className="p-3 space-y-2">
          {section.hint && <p className="text-2xs text-nv-textMuted">{section.hint}</p>}
          <table className="w-full text-2xs">
            <tbody>
              {section.keys.map(({ key, label, kind }) => {
                const val = config[key];
                if (val == null || val === '') return null;
                return (
                  <tr key={key} className="border-t border-nv-borderLight first:border-t-0">
                    <td className="py-1.5 pr-3 text-nv-textSubtle whitespace-nowrap w-28">{label}</td>
                    <td className="py-1.5">
                      {kind === 'status' ? <StatusBadge value={val} /> : (
                        <code className="font-mono text-nv-text break-all">{String(val)}</code>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function LogConfigPanel({ config, engine }) {
  const [openSections, setOpenSections] = useState(() => new Set(['slow', 'general']));
  const extraKeys = useMemo(() => {
    const known = new Set(CONFIG_SECTIONS.flatMap((s) => s.keys.map((k) => k.key)));
    return Object.entries(config).filter(([k]) => !known.has(k));
  }, [config]);

  const slowOff = config.slow_query_log != null && !isOn(config.slow_query_log);
  const generalOff = config.general_log != null && !isOn(config.general_log);

  const toggleSection = (id) => {
    setOpenSections((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  return (
    <div className="flex-1 min-h-0 overflow-auto p-3 space-y-3">
      <div className="flex items-center gap-2 text-xs text-nv-textSubtle">
        <Settings2 size={14} className="text-sky-500" />
        <span>Configuración de logs · <span className="font-mono">{engine ?? '—'}</span></span>
      </div>

      {(slowOff || generalOff) && (
        <div className="text-2xs px-3 py-2 rounded border border-amber-800/40 bg-amber-950/25 text-amber-300 flex items-start gap-2">
          <AlertTriangle size={14} className="shrink-0 mt-0.5" />
          <span>
            {slowOff && 'Slow query log está OFF — no verás entradas en slow-query hasta activarlo en el servidor. '}
            {generalOff && 'General log está OFF.'}
          </span>
        </div>
      )}

      {CONFIG_SECTIONS.map((section) => (
        <ConfigSection
          key={section.id}
          section={section}
          config={config}
          expanded={openSections.has(section.id)}
          onToggle={() => toggleSection(section.id)}
        />
      ))}

      {extraKeys.length > 0 && (
        <div className="border border-nv-border rounded-lg overflow-hidden">
          <button
            type="button"
            className="w-full px-3 py-2 flex items-center gap-2 text-left hover:bg-nv-hover/60 text-xs font-semibold"
            onClick={() => toggleSection('_extra')}
          >
            {openSections.has('_extra') ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            Otras variables
          </button>
          {openSections.has('_extra') && (
            <pre className="p-3 text-2xs font-mono overflow-auto border-t border-nv-border bg-nv-bg/50">
              {JSON.stringify(Object.fromEntries(extraKeys), null, 2)}
            </pre>
          )}
        </div>
      )}

      {Object.keys(config).length === 0 && (
        <p className="text-nv-textMuted text-xs text-center py-8">Sin configuración disponible para este motor.</p>
      )}
    </div>
  );
}

const LOGS_AUTO_REFRESH_KEY = 'nv-logs-auto-refresh';
const LOGS_AUTO_REFRESH_INTERVAL_KEY = 'nv-logs-auto-refresh-interval';
const LOGS_REFRESH_INTERVALS = [
  { ms: 15000, label: '15s' },
  { ms: 30000, label: '30s' },
  { ms: 60000, label: '60s' },
];

function readLogsAutoRefresh() {
  try {
    return localStorage.getItem(LOGS_AUTO_REFRESH_KEY) === '1';
  } catch {
    return false;
  }
}

function readLogsRefreshInterval() {
  try {
    const v = parseInt(localStorage.getItem(LOGS_AUTO_REFRESH_INTERVAL_KEY) || '30000', 10);
    return LOGS_REFRESH_INTERVALS.some((x) => x.ms === v) ? v : 30000;
  } catch {
    return 30000;
  }
}

function openInQueryStore(connectionId, connectionName, sql) {
  const text = String(sql ?? '').trim();
  if (!text) return;
  openQueryStoreTab({ connectionId, connectionName });
  useQueryStoreNavStore.getState().openQuery({ connectionId, sqlText: text });
}

function CollapsibleCard({ expanded, onToggle, header, sql, actions, children, accent = 'sky' }) {
  const borderAccent = accent === 'amber' ? 'border-l-amber-500' : 'border-l-sky-500';
  const bgHeader = expanded ? 'bg-nv-panel/70' : 'bg-nv-panel/40';
  const sqlLine = sqlPreview(sql, 200);

  return (
    <div
      className={`border border-nv-border rounded-md overflow-hidden mb-1.5 border-l-[3px] ${expanded ? borderAccent : 'border-l-transparent'} transition-colors`}
    >
      <div className={`flex items-stretch gap-1 px-1.5 py-1.5 ${bgHeader}`}>
        <button
          type="button"
          className="shrink-0 px-1 hover:bg-nv-hover/60 rounded self-start mt-0.5"
          onClick={onToggle}
          aria-expanded={expanded}
        >
          {expanded ? <ChevronDown size={14} className="text-sky-500" /> : <ChevronRight size={14} className="text-nv-textMuted" />}
        </button>
        <button
          type="button"
          className="flex-1 min-w-0 text-left hover:bg-nv-hover/40 rounded px-1 py-0.5"
          onClick={onToggle}
        >
          <div className="flex items-center gap-2 flex-wrap text-2xs">{header}</div>
          <div className="font-mono text-2xs text-nv-text/90 truncate mt-0.5 pr-1" title={String(sql ?? '')}>
            {sqlLine}
          </div>
        </button>
        {actions && (
          <div className="shrink-0 self-center pr-1" onClick={(e) => e.stopPropagation()}>
            {actions}
          </div>
        )}
      </div>
      {expanded && <div className="border-t border-nv-border/60 bg-nv-bg/30">{children}</div>}
    </div>
  );
}

function QueryStoreButton({ connectionId, connectionName, sql }) {
  if (isLiteEdition) return null;
  return (
    <button
      type="button"
      className="nv-btn !py-0.5 !text-2xs whitespace-nowrap"
      title="Abrir en Query Store"
      onClick={() => openInQueryStore(connectionId, connectionName, sql)}
    >
      <Activity size={10} className="text-sky-500" /> Query Store
    </button>
  );
}

function SlowLogEntry({ row, index, expanded, onToggle, connectionId, connectionName }) {
  const querySec = parseQueryTimeSec(row.query_time ?? row.query_time_sec);
  const lockSec = parseQueryTimeSec(row.lock_time ?? row.lock_time_sec);
  const sql = sqlFromLogRow(row);
  const db = row.db ?? row.database ?? '—';
  const user = row.user_host ?? row.user ?? '—';

  return (
    <CollapsibleCard
      expanded={expanded}
      onToggle={onToggle}
      accent="amber"
      sql={sql}
      actions={<QueryStoreButton connectionId={connectionId} connectionName={connectionName} sql={sql} />}
      header={(
        <>
          <span className="font-mono text-amber-400/90 font-semibold">#{index + 1}</span>
          <span className="text-nv-textSubtle flex items-center gap-0.5"><Clock size={10} />{fmtTime(row.start_time ?? row.event_time)}</span>
          <span className="text-nv-textSubtle">{db}</span>
          <span className="font-semibold tabular-nums text-amber-300">{fmtDuration(querySec)}</span>
          <span className="text-nv-textMuted truncate max-w-[8rem] hidden md:inline" title={user}>{user}</span>
        </>
      )}
    >
      <div className="grid grid-cols-2 md:grid-cols-4 gap-1.5 p-2">
        <div className="px-2 py-1 rounded border border-nv-border bg-nv-panel/50 text-center">
          <div className="text-2xs text-nv-textSubtle">Query time</div>
          <div className="text-sm font-semibold tabular-nums text-amber-300">{fmtDuration(querySec)}</div>
        </div>
        <div className="px-2 py-1 rounded border border-nv-border bg-nv-panel/50 text-center">
          <div className="text-2xs text-nv-textSubtle">Lock time</div>
          <div className="text-sm font-semibold tabular-nums">{fmtDuration(lockSec)}</div>
        </div>
        <div className="px-2 py-1 rounded border border-nv-border bg-nv-panel/50 text-center">
          <div className="text-2xs text-nv-textSubtle">Rows sent</div>
          <div className="text-sm font-semibold tabular-nums">{row.rows_sent ?? '—'}</div>
        </div>
        <div className="px-2 py-1 rounded border border-nv-border bg-nv-panel/50 text-center">
          <div className="text-2xs text-nv-textSubtle">Rows examined</div>
          <div className="text-sm font-semibold tabular-nums">{row.rows_examined ?? '—'}</div>
        </div>
      </div>
      <div className="px-2 pb-2">
        <div className="text-2xs text-nv-textSubtle mb-1 flex items-center gap-1">
          <FileCode2 size={10} className="text-sky-500" /> SQL
        </div>
        <pre className="font-mono text-2xs whitespace-pre-wrap break-all text-nv-text leading-relaxed max-h-40 overflow-auto bg-nv-panel/60 rounded border border-nv-border p-2">
          {sql || '—'}
        </pre>
      </div>
    </CollapsibleCard>
  );
}

function GeneralLogEntry({ row, index, expanded, onToggle, connectionId, connectionName }) {
  const sql = sqlFromLogRow(row);
  const isQuery = /^(SELECT|WITH|INSERT|UPDATE|DELETE|SHOW|CALL)\b/i.test(String(sql).trim());
  return (
    <CollapsibleCard
      expanded={expanded}
      onToggle={onToggle}
      sql={sql}
      actions={isQuery ? <QueryStoreButton connectionId={connectionId} connectionName={connectionName} sql={sql} /> : null}
      header={(
        <>
          <span className="font-mono text-sky-400 font-semibold">#{index + 1}</span>
          <span className="text-nv-textSubtle">{fmtTime(row.event_time ?? row.start_time)}</span>
          <span className="px-1.5 py-0.5 rounded bg-nv-panel border border-nv-border">{row.command_type ?? '—'}</span>
          <span className="text-nv-textMuted truncate max-w-[10rem]" title={row.user_host}>{row.user_host ?? '—'}</span>
        </>
      )}
    >
      <pre className="p-2 font-mono text-2xs whitespace-pre-wrap break-all text-nv-text max-h-36 overflow-auto">
        {sql || '—'}
      </pre>
    </CollapsibleCard>
  );
}

export function ServerLogsPanel({ connectionId, connectionName }) {
  const [tab, setTab] = useState('slow-query');
  const [filter, setFilter] = useState('');
  const [sortKey, setSortKey] = useState('time');
  const [sortDir, setSortDir] = useState('desc');
  const [expanded, setExpanded] = useState(() => new Set());
  const [autoRefresh, setAutoRefresh] = useState(readLogsAutoRefresh);
  const [refreshIntervalMs, setRefreshIntervalMs] = useState(readLogsRefreshInterval);

  useEffect(() => {
    try {
      localStorage.setItem(LOGS_AUTO_REFRESH_KEY, autoRefresh ? '1' : '0');
      localStorage.setItem(LOGS_AUTO_REFRESH_INTERVAL_KEY, String(refreshIntervalMs));
    } catch {
      /* ignore */
    }
  }, [autoRefresh, refreshIntervalMs]);

  const pollMs = autoRefresh && tab !== 'config' ? refreshIntervalMs : false;

  const { data: configData, refetch: refetchConfig, isFetching: fc } = useQuery({
    queryKey: ['logs-config', connectionId],
    queryFn: () => api.logsConfig(connectionId),
  });
  const { data: slowData, refetch: refetchSlow, isFetching: fs, dataUpdatedAt: slowUpdatedAt } = useQuery({
    queryKey: ['logs-slow', connectionId],
    queryFn: () => api.logsSlowQuery(connectionId),
    enabled: tab === 'slow-query',
    refetchInterval: tab === 'slow-query' ? pollMs : false,
    refetchIntervalInBackground: false,
  });
  const { data: genData, refetch: refetchGen, isFetching: fg, dataUpdatedAt: genUpdatedAt } = useQuery({
    queryKey: ['logs-general', connectionId],
    queryFn: () => api.logsGeneral(connectionId),
    enabled: tab === 'general',
    refetchInterval: tab === 'general' ? pollMs : false,
    refetchIntervalInBackground: false,
  });

  const config = configData?.config ?? {};
  const engine = configData?.engine;
  const active = tab === 'slow-query' ? slowData : genData;
  const rawEntries = active?.entries;
  const entries = Array.isArray(rawEntries) ? rawEntries : [];
  const logError = active?.error ?? (rawEntries && !Array.isArray(rawEntries) ? String(rawEntries._error ?? 'Log unavailable') : null);
  const logHint = active?.hint ?? null;
  const logSource = active?.source ?? null;
  const refreshing = fc || fs || fg;
  const lastUpdatedAt = tab === 'slow-query' ? slowUpdatedAt : tab === 'general' ? genUpdatedAt : 0;
  const refreshIntervalLabel = LOGS_REFRESH_INTERVALS.find((x) => x.ms === refreshIntervalMs)?.label ?? '30s';

  const filteredSlow = useMemo(() => {
    const q = filter.trim().toLowerCase();
    let rows = entries;
    if (q) {
      rows = rows.filter((r) =>
        sqlFromLogRow(r).toLowerCase().includes(q)
        || String(r.db ?? '').toLowerCase().includes(q)
        || String(r.user_host ?? '').toLowerCase().includes(q),
      );
    }
    return [...rows].sort((a, b) => {
      let va;
      let vb;
      if (sortKey === 'query_time') {
        va = parseQueryTimeSec(a.query_time);
        vb = parseQueryTimeSec(b.query_time);
      } else if (sortKey === 'rows') {
        va = Number(a.rows_examined ?? 0);
        vb = Number(b.rows_examined ?? 0);
      } else {
        va = new Date(a.start_time ?? a.event_time ?? 0).getTime();
        vb = new Date(b.start_time ?? b.event_time ?? 0).getTime();
      }
      if (va === vb) return 0;
      return sortDir === 'asc' ? (va < vb ? -1 : 1) : (va > vb ? -1 : 1);
    });
  }, [entries, filter, sortKey, sortDir]);

  const filteredGeneral = useMemo(() => {
    const q = filter.trim().toLowerCase();
    if (!q) return entries;
    return entries.filter((r) =>
      String(r.argument ?? '').toLowerCase().includes(q)
      || String(r.command_type ?? '').toLowerCase().includes(q),
    );
  }, [entries, filter]);

  const listKey = tab === 'slow-query' ? `slow-${filteredSlow.length}` : `gen-${filteredGeneral.length}`;
  const activeList = tab === 'slow-query' ? filteredSlow : filteredGeneral;

  const toggleEntry = (key) => {
    setExpanded((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const expandAll = () => {
    setExpanded(new Set(activeList.map((_, i) => `${tab}-${i}`)));
  };

  const collapseAll = () => setExpanded(new Set());

  const isExpanded = (i) => expanded.has(`${tab}-${i}`);

  return (
    <div className="h-full flex flex-col bg-nv-bg min-h-0">
      <div className="flex items-center gap-2 px-2 py-1.5 bg-nv-toolbar border-b border-nv-border shrink-0 flex-wrap">
        <span className="font-semibold text-xs">Server Logs — {connectionName}</span>
        <div className="flex gap-1 ml-2 p-0.5 rounded border border-nv-border bg-nv-panel/80">
          {[
            { id: 'slow-query', label: 'Slow' },
            { id: 'general', label: 'General' },
            { id: 'config', label: 'Config' },
          ].map((t) => (
            <button
              key={t.id}
              type="button"
              className={`px-2.5 py-0.5 text-2xs rounded transition-colors ${
                tab === t.id ? 'bg-sky-700 text-white' : 'text-nv-textSubtle hover:bg-nv-hover'
              }`}
              onClick={() => setTab(t.id)}
            >
              {t.label}
            </button>
          ))}
        </div>
        {tab !== 'config' && (
          <>
            <div className="flex items-center gap-1 ml-1">
              <Search size={11} className="text-nv-textMuted" />
              <input
                className="nv-input !py-0.5 !text-2xs !h-6 w-36"
                placeholder="Filtrar…"
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
              />
              {tab === 'slow-query' && (
                <select
                  className="nv-input !py-0.5 !text-2xs !h-6"
                  value={sortKey}
                  onChange={(e) => setSortKey(e.target.value)}
                >
                  <option value="time">Fecha</option>
                  <option value="query_time">Query time</option>
                  <option value="rows">Rows examined</option>
                </select>
              )}
              {tab === 'slow-query' && (
                <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'))}>
                  {sortDir === 'asc' ? '↑' : '↓'}
                </button>
              )}
            </div>
            <div className="flex gap-1">
              <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={expandAll}>Expandir</button>
              <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={collapseAll}>Contraer</button>
            </div>
          </>
        )}
        {tab !== 'config' && (
          <div className="flex items-center gap-1.5 ml-auto">
            <label
              className={`flex items-center gap-1.5 px-2 py-0.5 rounded border text-2xs cursor-pointer select-none transition-colors ${
                autoRefresh
                  ? 'border-sky-700/60 bg-sky-950/30 text-sky-300'
                  : 'border-nv-border bg-nv-panel/50 text-nv-textSubtle hover:bg-nv-hover'
              }`}
              title="Actualizar logs automáticamente"
            >
              <input
                type="checkbox"
                className="sr-only"
                checked={autoRefresh}
                onChange={(e) => setAutoRefresh(e.target.checked)}
              />
              <Repeat size={11} className={autoRefresh && refreshing ? 'animate-spin' : ''} />
              Auto
            </label>
            <select
              className="nv-input !py-0.5 !text-2xs !h-6 !w-14"
              value={refreshIntervalMs}
              onChange={(e) => setRefreshIntervalMs(Number(e.target.value))}
              disabled={!autoRefresh}
              title="Intervalo de auto-refresh"
            >
              {LOGS_REFRESH_INTERVALS.map((opt) => (
                <option key={opt.ms} value={opt.ms}>{opt.label}</option>
              ))}
            </select>
            {autoRefresh && lastUpdatedAt > 0 && (
              <span className="text-2xs text-nv-textMuted hidden sm:inline" title="Última actualización">
                {fmtTime(lastUpdatedAt)}
              </span>
            )}
          </div>
        )}
        {tab === 'slow-query' && (
          <AiAnalysisButton
            connectionId={connectionId}
            kind="slow-log"
            params={{ limit: 50 }}
            identifier="slow-log"
            engine={engine}
            title="Análisis con IA — Slow Query Log"
            titleAttr="Analizar el slow query log con IA (diagnóstico y recomendaciones)"
          />
        )}
        {tab !== 'config' && (
          <ExportButtons
            rows={tab === 'slow-query' ? filteredSlow : filteredGeneral}
            filenamePrefix={`logs-${tab}-${connectionName ?? connectionId}`}
          />
        )}
        <button
          type="button"
          className={`nv-btn ${tab === 'config' ? 'ml-auto' : ''}`}
          onClick={() => { refetchConfig(); refetchSlow(); refetchGen(); }}
          title={autoRefresh && tab !== 'config' ? `Auto-refresh cada ${refreshIntervalLabel}` : 'Actualizar ahora'}
        >
          <RefreshCw size={11} className={refreshing ? 'animate-spin' : ''} />
        </button>
      </div>

      {tab === 'config' ? (
        <LogConfigPanel config={config} engine={engine} />
      ) : (
        <div className="flex-1 min-h-0 overflow-auto px-2 py-1.5" key={listKey}>
          {logError && (
            <p className="text-amber-400 p-2 border border-amber-700/50 rounded mb-2 text-2xs">{logError}</p>
          )}
          {logHint && (
            <p className="text-sky-300/90 p-2 border border-sky-800/40 rounded mb-2 text-2xs bg-sky-950/20">{logHint}</p>
          )}
          {logSource && entries.length > 0 && (
            <p className="text-2xs text-nv-textMuted px-1 py-1 mb-1">Fuente: <span className="font-mono">{logSource}</span></p>
          )}
          {entries.length === 0 && !logError && !logHint && (
            <p className="text-nv-textMuted p-4 text-center text-xs">No entries (log may be disabled or unavailable)</p>
          )}
          {tab === 'slow-query' && filteredSlow.length > 0 && (
            <div className="text-2xs text-nv-textMuted px-1 py-1 mb-1">{filteredSlow.length} entradas · clic para expandir</div>
          )}
          {tab === 'slow-query' && filteredSlow.map((row, i) => (
            <SlowLogEntry
              key={`slow-${i}-${row.start_time}`}
              row={row}
              index={i}
              expanded={isExpanded(i)}
              onToggle={() => toggleEntry(`${tab}-${i}`)}
              connectionId={connectionId}
              connectionName={connectionName}
            />
          ))}
          {tab === 'general' && filteredGeneral.map((row, i) => (
            <GeneralLogEntry
              key={`gen-${i}-${row.event_time}`}
              row={row}
              index={i}
              expanded={isExpanded(i)}
              onToggle={() => toggleEntry(`${tab}-${i}`)}
              connectionId={connectionId}
              connectionName={connectionName}
            />
          ))}
        </div>
      )}
    </div>
  );
}
